var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"오늘의 수업은 모의전투훈련으로 대체되었습니다!","JPN":"今日の授業は、模擬戦闘訓練になりました！","ENG":"Today's class will be substituted with simulation training!","TWN":"今天的課改成上模擬戰訓練！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STUDENT_EXTRA_NULL_NULL","text":{"KOREA":"선생님- 오늘은 이론교습을 할 거라고 하셨는데요?","JPN":"先生～今日は理論の教習をするって言ったじゃないですか～","ENG":"But Ms. Moore, you said we'd be doing theory today.","TWN":"老師～你不是說今天要上理論嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"어쩔 수 없어! 나이엘이 수업을 바꾸면 다음 유물탐사 때 도와준다고 했거든!","JPN":"仕方ないの！　ナイエルから授業を変えたら次の遺物探査を手伝ってあげるって言われたから！","ENG":"My hands are tied! Naielle said she'd help out on the next relic expedition if I changed classes!","TWN":"有什麼辦法！奈爾說這樣下次的遺物探索她才會幫忙！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"선생님… 그런 편파적인 거래는 징계 사유인 거 아시죠?","JPN":"先生……そんな不公平な取引は、懲戒の理由になるの知ってますよね？","ENG":"Uh, Ms. Moore...? You do know that exchanging favors with students is grounds for disciplinary action, right?","TWN":"老師…你知道跟學生私下交易會遭到懲戒的吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"될 대로 되라지! 난 벌써 일주일 넘게 탐험도 못 나가고 학교에만 나오고 있다고!","JPN":"なんとでも言ってちょうだい！　私はもう一週間以上も探検に出られないまま、学校に来ているのよ！","ENG":"Who cares?! I've done nothing but teaching for over a week! I wanna go explore!","TWN":"我管不了這麼多啦！我已經超過一個禮拜只有來學校，都沒有去探險欸！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"우와, 너무 뻔뻔하니까 지적도 못 하겠어.","JPN":"うわ、ふてぶてしすぎて突っこめない。","ENG":"Whoa... You're so shameless, I'm lost for words.","TWN":"哇，還這麼理直氣壯的，好像拿你沒辦法。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"후후후…","JPN":"ふふふ……","ENG":"Hah hah hah...","TWN":"呵呵呵…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"모의전투훈련이라면, 마음에 안 드는 녀석을 실컷 혼쭐을 내줘도 뭐라 할 사람이 없지.","JPN":"模擬戦闘訓練なら、気に入らないやつを思いっきりこらしめてやっても誰も指摘してこないよね。","ENG":"If it is in a simulation training, no one can say anything to me for bullying someone I don't like.","TWN":"模擬戰訓練的時候，可以狠狠教訓那個討厭鬼也不會有人說什麼。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"시엘이라고 했던가? 이번 기회에 저 건방진 사이코패스 신입생 녀석을 엉망진창으로 만들어주겠어.","JPN":"シエルだっけ？　この機会に、あの生意気なサイコパス新入生をめちゃくちゃにしてやる。","ENG":"Ciel, was it? I'll make sure to teach that arrogant psychopath a lesson!","TWN":"她叫希爾是吧？看我怎麼教訓那個囂張的神經病新生！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"자, 그럼 대진표를 짜볼까? 전투상대는 공평하게 제비뽑기로…","JPN":"さてと、トーナメント表を作ってみようか？　戦闘相手は公正にくじ引きで……","ENG":"Okay, then. Let's see who goes up against whom. We'll draw lots to be fair...","TWN":"好～那我們先來分組吧？公平起見用抽籤的…"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"선생님? 제 상대는 적당히 강한 애로 정해뒀어요.","JPN":"先生？　私の相手は適当に強い子に決めておきました。","ENG":"Ms. Moore? I have someone in mind who I want to spar with.","TWN":"老師，我已經選好一個厲害的人來當我的對手。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"어차피 약한 녀석이 걸려봐야, 너무 일방적이라서 연습거리도 안 될 테니까. 피차 손해잖아요?","JPN":"どうせ弱いやつが当たっても、私の練習相手にもなりませんし、お互い損でしょ？","ENG":"If I get someone weak, it'll be too one-sided and a loss for both of us, don't you think?","TWN":"要是實力相差太懸殊，弱的那方只有被輾壓的份，這樣根本無法學到東西吧？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"음! 나이엘이 하는 말치곤 제법 일리가 있네!","JPN":"そうね！　ナイエルにしてはその考え一理あるわね！","ENG":"Mm! You sometimes make a good point, Naielle!","TWN":"嗯！奈爾這次倒是說的蠻有道理的！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HANDGUN_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 각자 상대를 직접 정하는 걸로 하자!","JPN":"それじゃあ、各自相手を直接選ぶことにしましょう！","ENG":"Then, let's each choose who you want to spar with!","TWN":"那就自己選對手吧！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HANDGUN_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"거기 너! 유감스럽게도, 내 상대가 되어줘야겠어.","JPN":"そこのあんた！　残念だろうけど、私の相手になってもらうよ。","ENG":"Hey, you! Unlucky for you, I'm gonna spar with you.","TWN":"那個你！不好意思喔，你要當我的對手。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"…좋소.","JPN":"……よいでしょう。","ENG":"...Very well.","TWN":"…好。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그런데, 모의전투훈련이 정확히 무엇이오?","JPN":"ところで、模擬戦闘訓練とは正確には何でしょうか。","ENG":"However, what exactly is simulation training?","TWN":"不過模擬戰訓練的內容是什麼？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"규칙은 간단해. 한쪽이 리타이어 할 때까지 결투를 벌이는 거지.","JPN":"ルールは簡単。一方がリタイアするまで決闘を続けるんだよ。","ENG":"The rule is simple. You battle each other until one side retires.","TWN":"規則很簡單，就是戰到一方投降為止。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"규칙은 그것뿐?","JPN":"規則はそれだけですか？","ENG":"Is that the only rule?","TWN":"就這樣？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"더 이상의 자세한 규칙은 생략한다!","JPN":"これ以上の詳しいルールは省略！","ENG":"There are more, but they're nothing to be concerned about!","TWN":"其他詳細的規則省略！"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L30_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이런저런 규칙에 얽매여 서로 봐주다 보면, 나중에 있을 실전에 대비할 수 없잖아?","JPN":"あれこれルールに縛られてお互い手加減してると、後の実戦に備えられないでしょ？","ENG":"If we all abide by every single rule and go easy on one another, we can't prepare for a real battle, right?","TWN":"要是雙方因為這些麻煩的規則而綁手綁腳的，之後有辦法應付實戰嗎？"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"과연… 이해했소.","JPN":"なるほど……承知しました。","ENG":"I see... Understood.","TWN":"原來…明白了。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그럼 한 수 부탁하리다.","JPN":"それでは、お手柔らかにお願いいたします。","ENG":"Then, let us battle.","TWN":"那就出招吧。"},"stage":{"bg":"SCHOOL_SPRING","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};